import React, { useState } from 'react';
import axios from 'axios';

// Настраиваем axios на наш сервер
const API = axios.create({ baseURL: 'http://localhost:5000' });

function App() {
  const [isLogin, setIsLogin] = useState(true);
  const [formData, setFormData] = useState({
    email: '',
    username: '',
    displayName: '',
    password: '',
    login: ''
  });
  const [user, setUser] = useState(null);
  const [error, setError] = useState('');
  const [message, setMessage] = useState('');

  const handleRegister = async (e) => {
    e.preventDefault();
    setError('');
    setMessage('');
    
    try {
      const res = await API.post('/api/register', {
        email: formData.email,
        username: formData.username,
        displayName: formData.displayName,
        password: formData.password
      });
      
      setMessage('Регистрация успешна! Теперь войдите.');
      setFormData({ ...formData, email: '', username: '', displayName: '', password: '' });
      setIsLogin(true);
    } catch (err) {
      setError(err.response?.data?.error || 'Ошибка регистрации');
    }
  };

  const handleLogin = async (e) => {
    e.preventDefault();
    setError('');
    setMessage('');
    
    try {
      const res = await API.post('/api/login', {
        login: formData.login,
        password: formData.password
      });
      
      setUser(res.data.user);
      setMessage(`Добро пожаловать, ${res.data.user.displayName}!`);
    } catch (err) {
      setError(err.response?.data?.error || 'Ошибка входа');
    }
  };

  const handleLogout = () => {
    setUser(null);
    setMessage('');
  };

  if (user) {
    return (
      <div style={{ padding: '20px', fontFamily: 'Arial' }}>
        <h1>Chatty - Вы вошли как {user.displayName}</h1>
        <p>Email: {user.email}</p>
        <p>Username: @{user.username}</p>
        <button 
          onClick={handleLogout}
          style={{ padding: '10px 20px', background: '#f44336', color: 'white', border: 'none', borderRadius: '5px', cursor: 'pointer' }}
        >
          Выйти
        </button>
      </div>
    );
  }

  return (
    <div style={{ maxWidth: '400px', margin: '50px auto', padding: '20px', fontFamily: 'Arial' }}>
      <h1 style={{ textAlign: 'center' }}>Chatty</h1>
      
      <div style={{ display: 'flex', gap: '10px', marginBottom: '20px' }}>
        <button 
          onClick={() => setIsLogin(true)}
          style={{ 
            flex: 1, padding: '10px', 
            background: isLogin ? '#4CAF50' : '#f0f0f0',
            color: isLogin ? 'white' : 'black',
            border: 'none', 
            borderRadius: '5px',
            cursor: 'pointer'
          }}
        >
          Вход
        </button>
        <button 
          onClick={() => setIsLogin(false)}
          style={{ 
            flex: 1, padding: '10px',
            background: !isLogin ? '#4CAF50' : '#f0f0f0',
            color: !isLogin ? 'white' : 'black',
            border: 'none',
            borderRadius: '5px',
            cursor: 'pointer'
          }}
        >
          Регистрация
        </button>
      </div>

      {error && (
        <div style={{ background: '#ffebee', color: '#c62828', padding: '10px', borderRadius: '5px', marginBottom: '20px' }}>
          {error}
        </div>
      )}

      {message && (
        <div style={{ background: '#e8f5e8', color: '#2e7d32', padding: '10px', borderRadius: '5px', marginBottom: '20px' }}>
          {message}
        </div>
      )}

      {isLogin ? (
        <form onSubmit={handleLogin}>
          <div style={{ marginBottom: '15px' }}>
            <label style={{ display: 'block', marginBottom: '5px' }}>Email или Username:</label>
            <input
              type="text"
              value={formData.login}
              onChange={(e) => setFormData({...formData, login: e.target.value})}
              style={{ width: '100%', padding: '8px', border: '1px solid #ddd', borderRadius: '4px' }}
              required
            />
          </div>
          <div style={{ marginBottom: '15px' }}>
            <label style={{ display: 'block', marginBottom: '5px' }}>Пароль:</label>
            <input
              type="password"
              value={formData.password}
              onChange={(e) => setFormData({...formData, password: e.target.value})}
              style={{ width: '100%', padding: '8px', border: '1px solid #ddd', borderRadius: '4px' }}
              required
            />
          </div>
          <button 
            type="submit"
            style={{ width: '100%', padding: '10px', background: '#4CAF50', color: 'white', border: 'none', borderRadius: '5px', cursor: 'pointer' }}
          >
            Войти
          </button>
        </form>
      ) : (
        <form onSubmit={handleRegister}>
          <div style={{ marginBottom: '15px' }}>
            <label style={{ display: 'block', marginBottom: '5px' }}>Email:</label>
            <input
              type="email"
              value={formData.email}
              onChange={(e) => setFormData({...formData, email: e.target.value})}
              style={{ width: '100%', padding: '8px', border: '1px solid #ddd', borderRadius: '4px' }}
              required
            />
          </div>
          <div style={{ marginBottom: '15px' }}>
            <label style={{ display: 'block', marginBottom: '5px' }}>Username:</label>
            <input
              type="text"
              value={formData.username}
              onChange={(e) => setFormData({...formData, username: e.target.value})}
              style={{ width: '100%', padding: '8px', border: '1px solid #ddd', borderRadius: '4px' }}
              required
            />
          </div>
          <div style={{ marginBottom: '15px' }}>
            <label style={{ display: 'block', marginBottom: '5px' }}>Имя (отображается):</label>
            <input
              type="text"
              value={formData.displayName}
              onChange={(e) => setFormData({...formData, displayName: e.target.value})}
              style={{ width: '100%', padding: '8px', border: '1px solid #ddd', borderRadius: '4px' }}
              required
            />
          </div>
          <div style={{ marginBottom: '15px' }}>
            <label style={{ display: 'block', marginBottom: '5px' }}>Пароль:</label>
            <input
              type="password"
              value={formData.password}
              onChange={(e) => setFormData({...formData, password: e.target.value})}
              style={{ width: '100%', padding: '8px', border: '1px solid #ddd', borderRadius: '4px' }}
              required
            />
          </div>
          <button 
            type="submit"
            style={{ width: '100%', padding: '10px', background: '#4CAF50', color: 'white', border: 'none', borderRadius: '5px', cursor: 'pointer' }}
          >
            Зарегистрироваться
          </button>
        </form>
      )}
    </div>
  );
}

export default App;
